insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q001', (select id from chapters where code='soc-geo'), 301, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'What are the three categories of natural resources based on their use?', null, '["Resources essential for life, resources for materials, resources for energy", "Renewable resources, non-renewable resources, and recyclable resources", "Water resources, mineral resources, and biological resources", "Land resources, water resources, and air resources"]'::jsonb, 0, 'Resources essential for life, resources for materials, resources for energy', 'The chapter categorizes natural resources based on their use into three types: essential for life, for materials, and for energy.  ▸ Textbook: One of the ways we could categorise natural resources is based on the uses we put them to — essential for our life, source for materials and sources f');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q002', (select id from chapters where code='soc-geo'), 302, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'Which of the following is a renewable resource?', null, '["Coal", "Petroleum", "Solar energy", "Natural gas"]'::jsonb, 2, 'Solar energy', 'Solar energy is renewable because it can be replenished naturally and sustainably.  ▸ Textbook: Solar energy, wind energy, energy from flowing water, timber from forests are renewable resources as long as we are able to manage them in a sustainab');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q003', (select id from chapters where code='soc-geo'), 302, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is the main condition for a resource to be considered renewable?', null, '["It must be economically feasible to extract", "It must be technologically accessible", "The natural rhythm of restoration and regeneration must not be disturbed", "It must be culturally acceptable to use"]'::jsonb, 2, 'The natural rhythm of restoration and regeneration must not be disturbed', 'Renewable resources must be managed so that their natural cycles of restoration and regeneration are not disrupted.  ▸ Textbook: However, for them to remain renewable there is a condition — the natural rhythm of restoration and regeneration must not be disturbed.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q004', (select id from chapters where code='soc-geo'), 303, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'Which state in India is facing a severe groundwater depletion crisis due to overexploitation?', null, '["Rajasthan", "Punjab", "Kerala", "Tamil Nadu"]'::jsonb, 1, 'Punjab', 'Punjab is highlighted in the chapter as facing a groundwater crisis due to overuse.  ▸ Textbook: A crisis has unfolded in the fertile plains of Punjab where groundwater resources have been severely depleted.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q005', (select id from chapters where code='soc-geo'), 303, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is the ''paradox of plenty''?', null, '["Having abundant resources leads to economic prosperity", "Abundant resources guarantee sustainable development", "Regions rich in resources can experience slower economic growth", "Natural resources are evenly distributed across the world"]'::jsonb, 2, 'Regions rich in resources can experience slower economic growth', 'The paradox of plenty refers to the situation where resource-rich regions do not necessarily experience economic prosperity.  ▸ Textbook: Some regions rich in natural resources can experience slower economic growth and development — a phenomenon economists call the ‘natural resource curs');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q007', (select id from chapters where code='soc-geo'), 303, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is the primary reason for the uneven distribution of natural resources?', null, '["Human intervention", "Geographical factors", "Technological advancement", "Cultural practices"]'::jsonb, 1, 'Geographical factors', 'Geographical factors lead to the uneven distribution of resources across different regions.  ▸ Textbook: Natural resources are not evenly distributed across our planet or even within countries.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q008', (select id from chapters where code='soc-geo'), 304, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'Which practice is an example of conservation and stewardship?', null, '["Overfishing during spawning season", "Using chemical fertilizers excessively", "Practicing organic farming", "Clearing forests for agriculture"]'::jsonb, 2, 'Practicing organic farming', 'Organic farming involves using natural methods to conserve resources and maintain ecological balance.  ▸ Textbook: Practices like the use of cow dung and other natural fertilisers, mulching, multi-cropping, and so on, enabled holistic soil management.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q009', (select id from chapters where code='soc-geo'), 304, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is the main implication of unsustainable use of natural resources?', null, '["Increased biodiversity", "Economic prosperity", "Environmental degradation", "Technological advancement"]'::jsonb, 2, 'Environmental degradation', 'Unsustainable use leads to environmental issues like pollution and biodiversity loss.  ▸ Textbook: Scientists studying these aspects have warned that the irresponsible treatment of natural resources has led to pollution, biodiversity loss and climat');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q010', (select id from chapters where code='soc-geo'), 301, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'Which of the following resources is essential for life?', null, '["Gold", "Air", "Coal", "Iron"]'::jsonb, 1, 'Air', 'Air is essential for life as it is necessary for breathing.  ▸ Textbook: Life could not exist on Earth without the air we breathe, the water we drink and the food we eat.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q011', (select id from chapters where code='soc-geo'), 302, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'What is a key characteristic of non-renewable resources?', null, '["They can be replenished quickly", "They are abundant in nature", "They are created over long periods", "They are always environmentally friendly"]'::jsonb, 2, 'They are created over long periods', 'Non-renewable resources take a long time to form and cannot be quickly replenished.  ▸ Textbook: Non-renewable resources are created over long periods. They cannot be replenished at the rate we use them.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q012', (select id from chapters where code='soc-geo'), 301, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'Which of the following is an example of a resource for materials?', null, '["Air", "Water", "Wood", "Sunlight"]'::jsonb, 2, 'Wood', 'Wood is used to create materials like furniture and art.  ▸ Textbook: Human beings create physical objects out of Nature’s gifts. We make them for our utility or to create things of beauty that enrich our lives and those');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q013', (select id from chapters where code='soc-geo'), 304, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is the role of the Central Pollution Control Board regarding cement factories?', null, '["To increase production", "To ensure pollution is minimized", "To promote cement exports", "To close down all cement factories"]'::jsonb, 1, 'To ensure pollution is minimized', 'The board sets guidelines to reduce pollution from cement production.  ▸ Textbook: The Central Pollution Control Board has created guidelines for cement factories to ensure that the pollution is minimised or eliminated.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q014', (select id from chapters where code='soc-geo'), 301, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'Which natural resource is primarily used for energy?', null, '["Marble", "Coal", "Gold", "Timber"]'::jsonb, 1, 'Coal', 'Coal is a major source of energy used for electricity and heating.  ▸ Textbook: This energy can come from diverse natural sources: coal, water, petroleum, natural gas, sunlight, wind, etc.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q015', (select id from chapters where code='soc-geo'), 303, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is the impact of over-pumping groundwater in Punjab?', null, '["Increased water availability", "Improved soil quality", "Depletion of groundwater resources", "Reduction in agricultural productivity"]'::jsonb, 2, 'Depletion of groundwater resources', 'Over-pumping has led to a significant depletion of groundwater resources.  ▸ Textbook: Almost 80% of the area of Punjab has been classified as ‘over-exploited’; in other words, we have drawn water at a rate much greater than at which res');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q016', (select id from chapters where code='soc-geo'), 304, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'Which of the following is a traditional practice that helps in soil management?', null, '["Using chemical fertilizers", "Monocropping", "Mulching", "Deforestation"]'::jsonb, 2, 'Mulching', 'Mulching is a traditional practice that helps retain soil moisture and improve fertility.  ▸ Textbook: Practices like the use of cow dung and other natural fertilisers, mulching, multi-cropping, and so on, enabled holistic soil management.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q017', (select id from chapters where code='soc-geo'), 303, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is the main reason for the ''natural resource curse''?', null, '["Lack of natural resources", "Over-reliance on resource extraction", "Abundant technological resources", "Equal distribution of resources"]'::jsonb, 1, 'Over-reliance on resource extraction', 'The curse occurs when economies rely too much on resource extraction without developing other industries.  ▸ Textbook: Frequently, economies are unable to develop industries that convert the resources into products of higher value; the chapter ‘Factors of Production’ i');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q019', (select id from chapters where code='soc-geo'), 303, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is the primary use of iron ore in India?', null, '["Jewelry making", "Construction", "Energy production", "Agricultural tools"]'::jsonb, 1, 'Construction', 'Iron ore is primarily used in construction and manufacturing industries.  ▸ Textbook: India’s geographical diversity provides us with a wide variety of natural resources, from wood to marble, and coal to gold.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q020', (select id from chapters where code='soc-geo'), 304, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'Which of the following practices can help in the conservation of water resources?', null, '["Over-irrigation", "Rainwater harvesting", "Deforestation", "Chemical pollution"]'::jsonb, 1, 'Rainwater harvesting', 'Rainwater harvesting helps conserve water by collecting and storing rainwater for future use.  ▸ Textbook: Traditional practices of water harvesting, rejuvenation of ponds and tanks, cutting down on wasteful consumption of water, processing and reusing wate');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q021', (select id from chapters where code='soc-geo'), 304, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is the main challenge in managing natural resources sustainably?', null, '["Lack of technology", "Political boundaries", "Balancing extraction with sustainability", "Abundance of resources"]'::jsonb, 2, 'Balancing extraction with sustainability', 'The main challenge is to extract resources without compromising their sustainability for future generations.  ▸ Textbook: However, the challenge of balancing resource extraction with sustainability remains.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q023', (select id from chapters where code='soc-geo'), 304, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is the significance of the Vṛikṣhāyurveda in resource management?', null, '["It promotes chemical fertilizers", "It focuses on sustainable agriculture", "It encourages deforestation", "It supports monocropping"]'::jsonb, 1, 'It focuses on sustainable agriculture', 'Vṛikṣhāyurveda promotes sustainable agricultural practices that maintain ecological balance.  ▸ Textbook: Vṛikṣhāyurveda is an ancient Indian botanical science that focuses on the study and care of plants and trees.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q025', (select id from chapters where code='soc-geo'), 304, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is the impact of industrial waste on natural resources?', null, '["Enhances soil fertility", "Increases biodiversity", "Disturbs Nature’s cycle of restoration and regeneration", "Improves water quality"]'::jsonb, 2, 'Disturbs Nature’s cycle of restoration and regeneration', 'Industrial waste can disrupt natural cycles, leading to pollution and environmental degradation.  ▸ Textbook: Instead, it leads to a disturbance in Nature’s cycle of restoration and regeneration, leading to a situation where the river becomes poisonous and can');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q026', (select id from chapters where code='soc-geo'), 304, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'Which of the following is a traditional method to maintain fish populations?', null, '["Overfishing", "Fishing during spawning season", "Regulating fishing during spawning season", "Using chemical baits"]'::jsonb, 2, 'Regulating fishing during spawning season', 'Regulating fishing during spawning helps maintain fish populations by allowing them to reproduce.  ▸ Textbook: Traditionally, communities had a system of regulating (or refraining from) fishing during the spawning season to enable the maintenance of the fish po');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q027', (select id from chapters where code='soc-geo'), 304, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is the role of human knowledge in resource management?', null, '["To exploit resources without limits", "To ensure resources are used sustainably", "To ignore resource distribution", "To prioritize non-renewable resources"]'::jsonb, 1, 'To ensure resources are used sustainably', 'Human knowledge helps in planning and managing resources sustainably for long-term benefits.  ▸ Textbook: Understanding and managing natural resources is a valuable starting point, but human knowledge, good governance, and strategic planning determine whet');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-q029', (select id from chapters where code='soc-geo'), 303, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is the primary challenge in sharing natural resources across political boundaries?', null, '["Technological limitations", "Cultural differences", "Tensions and conflicts", "Abundance of resources"]'::jsonb, 2, 'Tensions and conflicts', 'Sharing resources across boundaries can lead to tensions and conflicts due to differing interests.  ▸ Textbook: Nature does not pay attention to political boundaries. This leads to tensions regarding the sharing of natural resources across states as well as coun');
