insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-q003', (select id from chapters where code='soc-hist'), 308, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'Which ruler was known for the construction of the Sūrya temple at Konark?', null, '["Ala-ud-din Khilji", "Narasimhadeva I", "Muhammad bin Tughlaq", "Krishnadevaraya"]'::jsonb, 1, 'Narasimhadeva I', 'Narasimhadeva I built the Sūrya temple to commemorate his victories.  ▸ Textbook: Partly to commemorate these victories, he built the famed Sūrya temple at Konark (present-day Odisha).');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-q004', (select id from chapters where code='soc-hist'), 307, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'What was the outcome of the First Battle of Panipat in 1526?', null, '["Babur''s victory established the Mughal Empire", "The Delhi Sultanate expanded its territory", "The Vijayanagara Empire was defeated", "The Bahmani Sultanate was established"]'::jsonb, 0, 'Babur''s victory established the Mughal Empire', 'Babur''s victory in this battle led to the establishment of the Mughal Empire.  ▸ Textbook: 1526: First Battle of Panipat; Babur’s victory establishes the Mughal Empire');
