insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-civ-q027', (select id from chapters where code='soc-civ'), 313, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'What is the significance of the ''First-Past-the-Post'' system?', null, '["Candidate with most votes wins", "Proportional representation", "Single transferable vote", "Mixed-Member Proportional"]'::jsonb, 0, 'Candidate with most votes wins', 'In this system, the candidate with the most votes wins.  ▸ Textbook: India uses the ‘First-Past-the-Post’ electoral system, wherein the candidate receiving the most votes in a constituency wins.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-fp001', (select id from chapters where code='soc-geo'), 314, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'In many indigenous traditions, how is Nature viewed?', null, '["As a sacred entity", "As a resource to exploit", "As a scientific phenomenon", "As an economic asset"]'::jsonb, 0, 'As a sacred entity', 'The fine print mentions that Nature is considered sacred in many indigenous traditions.  ▸ Textbook: In many indigenous traditions of the world, Nature is considered sacred.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-fp002', (select id from chapters where code='soc-geo'), 314, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is an example of an ecosystem service?', null, '["Trees producing oxygen", "Animals migrating", "Rivers flowing", "Mountains forming"]'::jsonb, 0, 'Trees producing oxygen', 'The fine print explains that trees producing oxygen is an example of an ecosystem service.  ▸ Textbook: For example, trees naturally produce oxygen. When these natural processes benefit humans, we call them ‘ecosystem services’.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-fp004', (select id from chapters where code='soc-geo'), 314, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'Which river is the Mettur dam in Tamil Nadu built on?', null, '["Kaveri river", "Ganga river", "Yamuna river", "Godavari river"]'::jsonb, 0, 'Kaveri river', 'The fine print specifies that the Mettur dam is built on the Kaveri river.  ▸ Textbook: Fig. 1.13. Mettur dam in Tamil Nadu built on the Kaveri river');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-geo-fp009', (select id from chapters where code='soc-geo'), 314, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'What does the fine print suggest about the origin of things around us?', null, '["They all lead to Nature", "They are man-made", "They are from outer space", "They are eternal"]'::jsonb, 0, 'They all lead to Nature', 'The fine print suggests that everything ultimately originates from Nature.  ▸ Textbook: At some point they all lead to Nature; even the plastic button on your shirt.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-fp001', (select id from chapters where code='soc-hist'), 315, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'Which term is used in English to refer to statues used for worship in temples or homes, as it is considered neutral?', null, '["Idol", "Icon", "Image", "Mūrti"]'::jsonb, 2, 'Image', 'The term ''image'' is used because ''idol'' and ''icon'' are considered pejorative in certain religious contexts.  ▸ Textbook: In English, ‘image’ is a neutral term.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-fp002', (select id from chapters where code='soc-hist'), 315, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'Who were the Telugu chieftains that rallied over 75 more chieftains to form a confederacy against the Delhi Sultanate?', null, '["Hoysalas", "Musunuri Nayakas", "Eastern Gangas", "Vijayanagara Kings"]'::jsonb, 1, 'Musunuri Nayakas', 'The Musunuri Nayakas were key figures in resisting the Delhi Sultanate''s forces.  ▸ Textbook: During the time of the Tughlaqs, the Musunuri Nayakas, Telugu chieftains, rallied over 75 more chieftains of the region.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-fp003', (select id from chapters where code='soc-hist'), 315, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'What remarkable sight did Harihara and Bukka witness at Hampi according to popular folklore?', null, '["A lion chasing a deer", "A hare turning around and chasing a pack of hounds", "An eagle catching a snake", "A tiger swimming across a river"]'::jsonb, 1, 'A hare turning around and chasing a pack of hounds', 'This sight was interpreted as a symbol of resilience and bravery.  ▸ Textbook: According to popular folklore, Harihara and Bukka witnessed a remarkable sight at Hampi (in present-day Karnataka) — a hare turning around and chasing');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-fp004', (select id from chapters where code='soc-hist'), 315, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'Which Portuguese traveller left a detailed record of his stay in the Vijayanagara capital?', null, '["Vasco da Gama", "Ferdinand Magellan", "Domingo Paes", "Christopher Columbus"]'::jsonb, 2, 'Domingo Paes', 'Domingo Paes documented his observations of the Vijayanagara Empire.  ▸ Textbook: One of them, Domingo Paes, left a long and detailed record of his stay in the Vijayanagara capital.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-fp005', (select id from chapters where code='soc-hist'), 315, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'What does the term ''pati'' mean in titles like ''Gajapati''?', null, '["Warrior", "Priest", "Lord", "Merchant"]'::jsonb, 2, 'Lord', '''Pati'' signifies authority and leadership in titles.  ▸ Textbook: Pati means ‘lord’ or ‘master’ and was commonly used by many ruling dynasties of this period to signify power and stature.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-fp006', (select id from chapters where code='soc-hist'), 315, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'Which Sikh Guru was beheaded by Aurangzeb in 1675 at the site marked by Gurudwara Sis Ganj Sahib?', null, '["Guru Nanak", "Guru Gobind Singh", "Guru Tegh Bahadur", "Guru Arjan Dev"]'::jsonb, 2, 'Guru Tegh Bahadur', 'Guru Tegh Bahadur''s sacrifice is commemorated at this site.  ▸ Textbook: This one marks the site where Guru Tegh Bahadur, the ninth Sikh Guru, was beheaded by Aurangzeb in 1675.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-fp007', (select id from chapters where code='soc-hist'), 315, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What was the primary function of a ''hundi'' in historical trade networks?', null, '["To transport goods", "To serve as a currency", "To make payment instructions", "To record trade agreements"]'::jsonb, 2, 'To make payment instructions', 'Hundis facilitated financial transactions across borders without physical currency.  ▸ Textbook: A hundi was a written instruction to make payment to an individual.');
