insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-fp010', (select id from chapters where code='soc-hist'), 315, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What does the Gurudwara Sis Ganj Sahib in Chandni Chowk signify?', null, '["The birth of Guru Nanak", "The martyrdom of Guru Arjan Dev", "The beheading of Guru Tegh Bahadur", "The establishment of the Khalsa"]'::jsonb, 2, 'The beheading of Guru Tegh Bahadur', 'The Gurudwara commemorates the sacrifice of Guru Tegh Bahadur.  ▸ Textbook: This one marks the site where Guru Tegh Bahadur, the ninth Sikh Guru, was beheaded by Aurangzeb in 1675.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-fp011', (select id from chapters where code='soc-hist'), 315, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'Which empire''s capital did Harihara and Bukka establish at Hampi?', null, '["Mughal Empire", "Vijayanagara Empire", "Maratha Empire", "Delhi Sultanate"]'::jsonb, 1, 'Vijayanagara Empire', 'Hampi became the capital of the Vijayanagara Empire.  ▸ Textbook: advised them to establish their capital at that very spot.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-fp012', (select id from chapters where code='soc-hist'), 315, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What was the primary reason Portuguese travellers were well treated in Vijayanagara?', null, '["They brought precious spices", "They were allies in warfare", "They sold horses", "They introduced new technologies"]'::jsonb, 2, 'They sold horses', 'The king valued the horses for military purposes and wanted to prevent them from reaching enemies.  ▸ Textbook: Portuguese travellers, in particular, were very well treated, as they came to sell horses and the king did not want them to go and sell those precious');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-civ-fp001', (select id from chapters where code='soc-civ'), 316, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'How many elected representatives does India have in local government bodies?', null, '["3.1 million", "2.5 million", "1.3 million", "4 million"]'::jsonb, 0, '3.1 million', 'The fine print mentions the total number of elected representatives in local government bodies.  ▸ Textbook: India has 3.1 million elected representatives (1.3 million of them women) in more than 250,000 local government bodies across India.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-civ-fp002', (select id from chapters where code='soc-civ'), 316, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What unique method was used in the 10th century for selecting representatives according to the Uttaramerur inscriptions?', null, '["Drawing lots from a pot", "Voting by raising hands", "Secret ballot", "Voice vote"]'::jsonb, 0, 'Drawing lots from a pot', 'The method involved drawing lots from a pot as described in the inscriptions.  ▸ Textbook: The Uttaramerur inscriptions from the 10th century describe a transparent process for the selection of representatives. Eligible candidates’ names wer');
