insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-civ-fp004', (select id from chapters where code='soc-civ'), 316, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'Who became the Chief Election Commissioner of India in 1990 and introduced significant electoral reforms?', null, '["T.N. Seshan", "Sukumar Sen", "Sunil Arora", "Nasim Zaidi"]'::jsonb, 0, 'T.N. Seshan', 'T.N. Seshan is noted for his reforms in the electoral process.  ▸ Textbook: T.N. Seshan became the Chief Election Commissioner in 1990.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-civ-fp005', (select id from chapters where code='soc-civ'), 316, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'What is the term used for the legislative assembly in some regional languages?', null, '["Vidhan Sabha", "Lok Sabha", "Rajya Sabha", "Panchayat"]'::jsonb, 0, 'Vidhan Sabha', 'The fine print provides examples of regional names for the legislative assembly.  ▸ Textbook: The legislative assembly is called by several names in regional languages, for example, Vidhan Sabha and Niyama Sabha.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-civ-fp006', (select id from chapters where code='soc-civ'), 316, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'What option is available on the ballot for voters who do not wish to vote for any candidate?', null, '["NOTA", "Blank Vote", "Abstain", "Void"]'::jsonb, 0, 'NOTA', 'NOTA allows voters to express disapproval of all candidates.  ▸ Textbook: NOTA (None Of The Above) option is also available.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-civ-fp007', (select id from chapters where code='soc-civ'), 316, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What was one of the reforms introduced by T.N. Seshan to ensure free and fair elections?', null, '["Voter IDs to eliminate proxy voting", "Online voting system", "Extended voting hours", "Mandatory voting"]'::jsonb, 0, 'Voter IDs to eliminate proxy voting', 'Voter IDs were introduced to prevent proxy voting.  ▸ Textbook: T.N. Seshan brought in reforms to ensure free and fair elections, among them: campaigning to follow precise rules, voter IDs to eliminate proxy voting');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-civ-fp008', (select id from chapters where code='soc-civ'), 316, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'What is the cornerstone of Indian democracy?', null, '["Universal adult franchise", "Judicial independence", "Federal structure", "Economic equality"]'::jsonb, 0, 'Universal adult franchise', 'The right to vote for all adults is fundamental to Indian democracy.  ▸ Textbook: Universal adult franchise is the cornerstone of Indian democracy.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-civ-fp011', (select id from chapters where code='soc-civ'), 316, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What is the significance of the year 1913?', null, '["Women''s suffrage parade in the USA", "First Indian general election", "Formation of the Election Commission of India", "Introduction of electronic voting machines"]'::jsonb, 0, 'Women''s suffrage parade in the USA', 'The year marks an important event in the women''s suffrage movement.  ▸ Textbook: Fig. 5.3. Women’s suffrage parade, USA, 1913');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-adm001', (select id from chapters where code='soc-hist'), 309, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'Who was responsible for the translation of major Sanskrit texts into Persian during the Mughal period?', null, '["Akbar", "Babur", "Aurangzeb", "Shah Jahan"]'::jsonb, 0, 'Akbar', 'Akbar was keen on cultural integration and promoted the translation of important texts to bridge cultural gaps.  ▸ Textbook: He established a ‘house of translation’ at Fatehpur Sikri where he had major Sanskrit texts translated into Persian, including the Mahābhārata (Razmna');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-adm002', (select id from chapters where code='soc-hist'), 309, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'What was the primary reason Babur decided to stay and build his empire in India?', null, '["India''s wealth", "Fertile lands", "Strategic location", "Cultural diversity"]'::jsonb, 0, 'India''s wealth', 'Babur was attracted by the wealth of India, which influenced his decision to establish his empire there.  ▸ Textbook: Perhaps for the last reasons, especially India’s wealth, he decided to stay and build his empire in India rather than return to Central Asia.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-adm003', (select id from chapters where code='soc-hist'), 309, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'Which tax did Akbar abolish as part of his policy of religious tolerance?', null, '["Jizya", "Land revenue", "Trade tax", "Military tax"]'::jsonb, 0, 'Jizya', 'The abolition of the jizya was a significant step towards religious tolerance under Akbar''s rule.  ▸ Textbook: ...abolished the jizya, and promoted the doctrine of sulh-i-kul — literally, ‘peace with all’ or tolerance of all faiths.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-adm004', (select id from chapters where code='soc-hist'), 309, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What was the impact of Aurangzeb''s military campaigns on the Mughal Empire''s treasury?', null, '["Depleted the treasury", "Increased wealth", "Had no impact", "Led to economic growth"]'::jsonb, 0, 'Depleted the treasury', 'Aurangzeb''s extensive military campaigns were financially draining, contributing to the empire''s decline.  ▸ Textbook: Maintaining large armies for those campaigns depleted the empire’s treasury and put a great strain on the administration; indeed, this is often consid');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-adm006', (select id from chapters where code='soc-hist'), 309, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'How did Akbar''s approach to governance differ from earlier rulers of Delhi?', null, '["He employed political strategies", "He relied solely on military might", "He avoided any conquests", "He isolated his empire"]'::jsonb, 0, 'He employed political strategies', 'Akbar used a combination of political alliances and military strategies to expand and stabilize his empire.  ▸ Textbook: As his empire grew, he increasingly used political strategies to stabilise it; he entered into marriage alliances with princesses of neighbouring king');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-adm007', (select id from chapters where code='soc-hist'), 309, 'NCERT Social Science Grade 8', 2, 'medium', 120, 'mcq', 'What was one of the reasons for the frequent rebellions against the Mughal administration?', null, '["Harsh exploitation", "Religious tolerance", "Cultural diversity", "Economic prosperity"]'::jsonb, 0, 'Harsh exploitation', 'The oppressive policies and exploitation by the Mughal administration led to frequent rebellions.  ▸ Textbook: Over the centuries, many peasant communities rebelled against harsh exploitation.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-hist-adm008', (select id from chapters where code='soc-hist'), 309, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'What was the role of Abul Fazl in Akbar''s court?', null, '["Court historian and biographer", "Military commander", "Religious leader", "Architect"]'::jsonb, 0, 'Court historian and biographer', 'Abul Fazl was a key figure in documenting Akbar''s reign and policies.  ▸ Textbook: His court historian and biographer Abul Fazl recorded him as stating...');
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-geo'), 1, 'What natural resources are, and how we group them', '***', 'Natural resources: 32 of the 51 papers.', '[{"kind": "p", "text": "A NATURAL RESOURCE is any material or substance that occurs in Nature and is useful to humans — from the air we breathe to the coal we burn. Trace anything around you back far enough and it leads to Nature."}, {"kind": "key", "text": "One way to group resources is by their USE: (1) resources ESSENTIAL FOR LIFE — air, water, soil/food; (2) resources for MATERIALS — wood, marble, metals; (3) resources for ENERGY — coal, water, petroleum, sunlight, wind."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-geo'), 2, 'Renewable vs non-renewable', '***', 'The other way to group them.', '[{"kind": "key", "text": "RENEWABLE resources restore and regenerate themselves in a natural rhythm (sunlight, wind, water, forests) — as long as we do not disturb that rhythm by overusing them. NON-RENEWABLE resources form over very long periods and run out (coal, petroleum, minerals)."}, {"kind": "eg", "lines": ["Renewable: solar energy, wind, river water, forests.", "Non-renewable: coal, petroleum, natural gas, iron ore."]}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-geo'), 3, 'How resources are spread across India', '***', 'Distribution: 18 of 51 papers.', '[{"kind": "p", "text": "Resources are spread UNEVENLY because of geography — India has iron ore, coal, oil (e.g. Mumbai High) and water in different regions. This uneven spread can cause tensions when resources cross political boundaries."}, {"kind": "key", "text": "The PARADOX OF PLENTY (or ''resource curse''): a region RICH in resources can actually grow more SLOWLY, if it over-relies on extracting them. Punjab''s groundwater is being depleted by over-pumping."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-geo'), 4, 'Using resources wisely — stewardship', '***', 'Conservation: the biggest question set in Ch1.', '[{"kind": "key", "text": "STEWARDSHIP means using resources responsibly so future generations still have them. Overuse and industrial waste DISTURB Nature''s cycle of restoration and regeneration."}, {"kind": "eg", "lines": ["Organic farming (as in Sikkim, India''s first fully organic state).", "Solar energy (e.g. the solar farm near Raichur, Karnataka).", "Rainwater harvesting; mulching to retain soil moisture; regulating fishing during the spawning season."]}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-hist'), 1, 'The big picture and the timeline', '**', 'NEW to the 2026-27 syllabus — the old papers did not test it.', '[{"kind": "warn", "text": "This History chapter is NEW. Learn the timeline dates cold — they anchor everything."}, {"kind": "tbl", "head": ["Year", "Event"], "rows": [["1206", "The Delhi Sultanate is established"], ["1526", "First Battle of Panipat — Babur''s victory establishes the Mughal Empire"], ["1556", "Second Battle of Panipat — Akbar''s decisive victory"], ["1565", "Battle of Talikota — destruction of Vijayanagara city"], ["1671", "Battle of Saraighat — the Ahoms defeat the Mughals"], ["1699", "Formation of the Khalsa by Guru Gobind Singh"]]}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-hist'), 2, 'The Delhi Sultanate', '**', '', '[{"kind": "key", "text": "The Delhi Sultanate (from 1206) was ruled by a series of dynasties, ending with the LODIS. Ala-ud-din Khilji pushed south and repelled Mongol invasions; Muhammad bin Tughlaq moved the capital from Delhi to DAULATABAD (an ambitious but poorly executed scheme). Timur''s invasion left Delhi in ruins."}, {"kind": "p", "text": "Some sultans imposed the JIZYA — a tax on non-Muslim subjects in return for protection and exemption from military service."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-hist'), 3, 'The Vijayanagara Empire', '**', '', '[{"kind": "key", "text": "Founded by HARIHARA and BUKKA, with its capital at HAMPI. It reached its peak under KRISHNADEVA RAYA — a time of military power and cultural renaissance. Portuguese travellers like Domingo Paes visited and left detailed records. It declined after defeat at the Battle of TALIKOTA (1565)."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-hist'), 4, 'The Mughals', '**', '', '[{"kind": "key", "text": "BABUR defeated Ibrahim Lodi at the First Battle of PANIPAT (1526), establishing the Mughal Empire. He wrote the Baburnama and found India a ''country of few charms''. AKBAR won the Second Battle of Panipat (1556) and built a strong administrative framework — his court historian was ABUL FAZL, and he abolished the jizya."}, {"kind": "p", "text": "Sher Shah Suri briefly established the Sur Empire after defeating Humayun. In the Mughal administration the MIR BAKHSHI looked after military matters."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-hist'), 5, 'Resistance to the empires', '**', '', '[{"kind": "key", "text": "RAJPUTS — Maharana Pratap resisted Akbar at the Battle of HALDIGHATI (1576). AHOMS — defeated the Mughals at the Battle of SARAIGHAT (1671). SIKHS — Guru Gobind Singh formed the KHALSA (1699); Guru Tegh Bahadur had earlier been executed by Aurangzeb (site of Gurudwara Sis Ganj Sahib)."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-civ'), 1, 'Universal adult franchise', '**', 'The foundation of the chapter.', '[{"kind": "key", "text": "UNIVERSAL ADULT FRANCHISE means every adult citizen (18 years and above) gets ONE vote — regardless of caste, religion, gender, wealth or education. It is guaranteed by ARTICLE 326 of the Constitution and is the cornerstone of Indian democracy."}, {"kind": "p", "text": "The system works to bridge barriers so everyone can vote — postal/home voting for the elderly and persons with disabilities, ramps and help at booths."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-civ'), 2, 'The Election Commission of India', '**', 'How elections are actually run.', '[{"kind": "key", "text": "The ELECTION COMMISSION OF INDIA (ECI) conducts elections to the Lok Sabha, State Assemblies, and the offices of President and Vice-President. It is headed by the CHIEF ELECTION COMMISSIONER. State Election Commissions handle panchayat and local-body polls."}, {"kind": "tbl", "head": ["Officer", "Level / role"], "rows": [["Chief Election Commissioner", "Heads the ECI; oversees the whole electoral process"], ["Chief Electoral Officer", "Oversees elections in a State/UT"], ["District Election Officer", "Oversees elections in a district"], ["Returning Officer (RO)", "Conducts the election in a constituency"], ["Electoral Registration Officer (ERO)", "Prepares and maintains the voters'' list"]]}, {"kind": "p", "text": "T.N. SESHAN, Chief Election Commissioner from 1990, introduced major reforms — including voter ID cards to stop proxy voting."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-civ'), 3, 'EVM, VVPAT and the Model Code', '**', '', '[{"kind": "key", "text": "Votes are cast on an EVM (Electronic Voting Machine). The VVPAT — Voter Verifiable Paper Audit Trail — prints a slip so the voter can confirm their vote, giving a paper trail. NOTA (''None Of The Above'') lets a voter reject all candidates."}, {"kind": "key", "text": "The MODEL CODE OF CONDUCT (MCC) is a set of rules all parties must follow once elections are announced, to ensure free and fair play (e.g. no bribing voters, no using government resources to campaign)."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-civ'), 4, 'Lok Sabha, Rajya Sabha and beyond', '**', 'Elections: 17 of the 51 papers.', '[{"kind": "tbl", "head": ["", "How chosen", "Key facts"], "rows": [["Lok Sabha", "directly elected, First-Past-the-Post (most votes wins)", "543 constituencies; SC and ST seats reserved"], ["Rajya Sabha", "INDIRECTLY elected by State Assemblies, single transferable vote", "6-year term; 12 members nominated by the President"], ["President / Vice-President", "elected INDIRECTLY by an electoral college of MPs and MLAs", "—"]]}, {"kind": "key", "text": "FIRST-PAST-THE-POST: whichever candidate gets the most votes in a constituency wins — they do not need a majority."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-geo'), 5, 'Textbook fine print — the bits schools ask about', '***', 'The school usually asks from the textbook side-boxes.', '[{"kind": "p", "text": "The school asks from the side-boxes (''DON''T MISS OUT'', ''THINK ABOUT IT'') and captions."}, {"kind": "key", "text": "In many indigenous Indian traditions, Nature is considered SACRED — a nurturer and nourisher (e.g. Tulasī puja for wellbeing)."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-hist'), 6, 'Textbook fine print — the bits schools ask about', '***', 'The school usually asks from the textbook side-boxes.', '[{"kind": "p", "text": "The ''Tapestry of the Past'' boxes carry testable detail:"}, {"kind": "eg", "lines": ["The MUSUNURI NAYAKAS (Telugu chieftains) rallied a confederacy against the Delhi Sultanate.", "Harihara and Bukka founded Vijayanagara at Hampi (folklore: a hare chasing hounds).", "Domingo Paes, a Portuguese traveller, recorded life in the Vijayanagara capital.", "Guru Tegh Bahadur was executed by Aurangzeb in 1675 — site of Gurudwara Sis Ganj Sahib.", "A HUNDI was used to make payment instructions in trade networks."]}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='soc-civ'), 5, 'Textbook fine print — the bits schools ask about', '***', 'The school usually asks from the textbook side-boxes.', '[{"kind": "p", "text": "The ''Governance and Democracy'' boxes carry testable detail:"}, {"kind": "eg", "lines": ["India has about 3.1 million elected representatives in local government bodies.", "The 10th-century Uttaramerur inscriptions describe choosing representatives by DRAWING LOTS from a pot.", "T.N. Seshan became Chief Election Commissioner in 1990 and introduced voter IDs."]}]'::jsonb);
